const xalarms = global.get("xalarms") || {}

if (msg.action) {
    if (msg.action === "changeSetting") {
        let { requestFrequency, requestTimeout,
            processesLimited, endpointConfigs, setEnableAll,
            setGetsysinfoAll, setGetsetupAll } = msg.payload
        requestFrequency && context.set("requestFrequency", requestFrequency);
        requestTimeout && context.set("requestTimeout", requestTimeout);
        processesLimited && context.set("processesLimited", processesLimited);
        endpointConfigs && context.set("endpointConfigs", endpointConfigs);
        requestFrequency = context.get("requestFrequency");
        requestTimeout = context.get("requestTimeout");
        processesLimited = context.get("processesLimited");
        endpointConfigs = context.get("endpointConfigs");
        setEnableAll && Object.values(context.get("threads") || {}).forEach(t => {
            t.enabled = true
        })
        setGetsysinfoAll && Object.values(context.get("threads") || {}).forEach(t => {
            t.sysinfoIsRequired = true
        })
        setGetsetupAll && Object.values(context.get("threads") || {}).forEach(t => {
            t.getsetupIsRequired = true
        })
        msg.payload = {
            requestFrequency,
            requestTimeout,
            processesLimited,
            endpointConfigs
        }
        setTopic("Change Setting")
    } else if (msg.action === "readThreads") {
        let { mac } = msg.payload
        if (mac) {
            msg.payload = context.get(`threads.${mac}`)
            setTopic("thread")
        } else {
            msg.payload = context.get("threads")
            setTopic("threads")
        }
    } else if (msg.action === "setThreads") {
        let { mac } = msg.payload
        if (mac) {
            let singleThread = context.get(`threads.${mac}`)
            Object.entries(msg.payload).forEach(([par, v]) => {
                singleThread[par] = v
            })
            msg.payload = context.get(`threads.${mac}`)
            setTopic("thread")
        } else {
            msg.payload = context.get("threads")
            setTopic("threads")
        }
    } else if (msg.action === "start") {
        inititate = true
        msg.payload = { inititate }
        setTopic("Initiate")
    } else if (msg.action === "enabled") {
        let { enabled } = msg.payload
        context.set("enabled", enabled ? !0 : !1)
        msg.payload = { enabled: context.get("enabled") }
        setTopic("Enabled")
    }
}

if (!inititate) {
    return msg
}
