const getsetupOnData = (currentContext, endpointConfig) => {
    return (data) => {
        let { mac } = currentContext
        let { host } = endpointConfig
        // currentContext.setup_data = { mac, ...data }
        xgetsetup[mac].setup_data = { mac, ts: new Date().getTime(), ...data }
        delete currentContext.setup_err
        delete xgetsetup[mac]?.setup_err
        delete xgetsetup[mac]?.setup_data?.alarmCategories;
        delete xgetsetup[mac]?.setup_data?.maps;
        delete xgetsetup[mac]?.setup_data?.dpu;

        let devices = xgetsetup[mac]?.setup_data?.devices;
        const deviceKeyDelete = ["cmds"];
        const genKeyToDelete = ["devcom", "dixelldev", "dstp", "desc"];

        for (let i in devices) {
            deviceKeyDelete.forEach(k => delete devices[i]?.[k]);
            delete devices[i]?.lng?.cmds;

            if (devices[i]?.gen) {
                genKeyToDelete.forEach(k => delete devices[i]?.gen[k]);
            }

            let devicesVrs = devices[i]?.vrs;
            for (let index_vrs in devicesVrs) {
                delete devicesVrs[index_vrs]?.cwi;
                delete devicesVrs[index_vrs]?.chartDef?.color;
            }
        }

        n && node.send({ payload: data, topic: "getsetup" })

        if (typeof data == "object") {
            if (data.error === "PERMISSION_DENIED") {
                login(currentContext, endpointConfig)
                return statusWithTs("error", mac, "getsetup", host)
            } else {
                currentContext.getsetupIsRequired = false
                return statusWithTs("ok", mac, "getsetup", host)
            }
        }
        return statusWithTs("error", mac, "getsetup.data", host)
    }
}
const streamOnData = (currentContext, endpointConfig) => {
    return async (data) => {
        let { mac } = currentContext
        let { host } = endpointConfig
        // currentContext.stream_data = { mac, ...data }
        xstream[mac].stream_data = { mac, ts: new Date().getTime(), ...data }
        delete currentContext.stream_err
        delete xstream[mac].stream_err
        n && node.send({ payload: data, topic: "stream" })
        let backlogs = flow.get("backlogs")
        delete backlogs[mac];

        delete xstream[mac]?.stream_data?.stream?.inputs;
        delete xstream[mac]?.stream_data?.stream?.outputs;

        if (typeof data == "object") {
            if (currentContext.sysinfoIsRequired) {
                await sysinfo(endpointConfig)
            }
            if (data.error === "PERMISSION_DENIED") {
                let result = await login(endpointConfig, stream)
                return result
            } else if (data.status === "ok") {
                await alarms(endpointConfig);
                if (currentContext.getsetupIsRequired) {
                    return await getsetup(endpointConfig)
                }
                let result = await login(endpointConfig, null, "refresh")
                if (result.result === "ok") {
                    result.part = "stream+refresh"
                    return result
                }
                return statusWithTs("ok", mac, "stream", host)
            }
        }
    }
}
const alarmsOnData = (currentContext, endpointConfig) => {
