        delete xlogin[mac]?.login_data?.user?.desktops;
        delete xlogin[mac]?.login_data?.user?.permissions;
        delete xlogin[mac]?.login_data?.user?.chart;
        delete xlogin[mac]?.login_data?.layout;

        if (data.status !== "ok" /*|| !(data.user) || !(data.user.sses)*/) {
            // currentContext.login_err = data
            xlogin[mac].login_err = { mac, ts: new Date().getTime(), data }
