                if (res.result === "error") {
                    res.part = "login.xj.invalid"
                }
                n && node.send({ payload: { res } })
                return res
            } else {
                return statusWithTs("error", mac, "login.xj", host)
            }
            // } else {
            //     node.send({ payload: endpointConfig.auth.username })
            //     return statusWithTs("error", mac, "login", host)
            // }
        } else {
            n && node.send({ payload: "login ok" });

            if (typeof callback === 'function') {
                n && node.send({ payload: "callstream" });
                return await callback(endpointConfig);
            }
            return statusWithTs("ok", mac, "login")
        }
    }
}
const sysinfo = (endpointConfig) => {
    let { mac, host, urls } = endpointConfig
    let currentContext = getThread(mac)
    if (!currentContext["enabled"]) {
        // Promise.resolve(() => { return statusWithTs("blocked", mac, "getsetup", host) })
        return Promise.resolve(statusWithTs("blocked", mac, "sysinfo disabled", host))
    }
    let controller = createTimeoutController()
    return fetch(urls.sysinfo, {
        method: "GET",
        ...commonOptions,
        signal: controller.signal,
        agent: (urls.getsetup.startsWith("https") && new https.Agent({ rejectUnauthorized: false })) || null
    })
        .then(res2JSON)
        .then(sysInfoOnData(currentContext, endpointConfig))
        .catch(err => {
            // currentContext.sysinfo_err = err
            xsysinfo[mac].sysinfo_err = { mac, ts: new Date().getTime(), ...err }
            n && node.send({ payload: err, topic: "sysinfo" })
            clearTimeout(controller.timeoutId);
            return statusWithTs("error", mac, "sysinfo", host)
        }).finally(r => {
            clearTimeout(controller.timeoutId);
        })
}
