const alarms = (endpointConfig) => {
    let { mac, host, urls } = endpointConfig;
    let currentContext = getThread(mac);
    if (!currentContext["enabled"]) {
        return Promise.resolve(statusWithTs("blocked", mac, "alarms disabled", host));
    }
    if (!xalarms[mac]) xalarms[mac] = {};
    // --- mutex เพื่อป้องกันการเรียกซ้อน ---
    if (xalarms[mac].alarmsRunning) {
        node.warn("alarms skipped (running) : " + mac);
        return Promise.resolve(statusWithTs("blocked", mac, "alarms", host));
    }
    xalarms[mac].alarmsRunning = true;

    let { login_data = {} } = xlogin[mac], { user = {} } = login_data, { sses } = user

    if (!sses) {
        xalarms[mac].alarms_err = { mac, ts: new Date().getTime(), error: "NO SSES" };
    }
    let params = new myURL.URLSearchParams();
    params.append("SSES", sses);
    params.append("action", "active_alarms");
    let controller = createTimeoutController();

    return fetch(urls.alarms, {
        method: "POST",
        body: params,
        ...commonOptions,
        signal: controller.signal,
        agent: (urls.alarms.startsWith("https") && new https.Agent({ rejectUnauthorized: false })) || null
    })
        .then(res2JSON)
        .then(alarmsOnData(currentContext, endpointConfig))
        .catch(err => {
            xalarms[mac].alarms_err = { mac, ts: new Date().getTime(), ...err }
            n && node.send({ payload: err, topic: "alarms catched 1" })
            clearTimeout(controller.timeoutId);
            return statusWithTs("timeout", mac, "alarms timeout", host)
        })
        .finally(() => {
            xalarms[mac].alarmsRunning = false;
            clearTimeout(controller.timeoutId);
        })
}

const login = (endpointConfig, callback, action) => {
    let { mac, host, urls, auth } = endpointConfig
    let { auth_mode, username, password } = auth
    let currentContext = getThread(mac)
    if (!currentContext["enabled"]) {
        // Promise.resolve(() => { return statusWithTs("blocked", mac, "stream", host) })
        return Promise.resolve(statusWithTs("blocked", mac, "login disabled", host))
    }
    let SSES;

    if (action === "refresh") {
        let { login_data = {} } = xlogin[mac], { user = {} } = login_data, { sses } = user
        SSES = sses
    }
    let params = {
        action: action || "login",
        auth_mode,
        username,
        password,
        initparam: -1,
        SSES
    }
    let controller = createTimeoutController()
    return fetch(urls.login, {
        method: "POST",
        body: params2Body(params),
        ...commonOptions,
        signal: controller.signal,
        agent: (urls.login.startsWith("https") && new https.Agent({ rejectUnauthorized: false })) || null
    })
        .then(res2JSON)
        .then(loginOnData(currentContext, callback, endpointConfig, action))
        .catch(err => {
            // currentContext.login_err = { mac, ...err }
            xlogin[mac].login_err = { mac, ts: new Date().getTime(), ...err }
            n && node.send({ payload: err, topic: "login" })
            clearTimeout(controller.timeoutId);
            return statusWithTs("error", mac, "login", host)
        }).finally(r => {
            clearTimeout(controller.timeoutId);
        })
}

