    context.completeds = 0;
    context.err = 0
    context.total = endpointConfigs.length
    node.send(msg)
    flow.set("backlogs", {})
    const tasks = endpointConfigs.map((endpointConfig) =>
        processed_withLimited(() => stream(endpointConfig).finally(() => {
            context.completeds = (context.completeds || 0) + 1;

            node.status({ fill: "yellow", shape: "dot", text: `Running ${context.completeds}/${context.total} err:${context.err || 0}` });
