    Promise.allSettled(tasks).then((results) => {
        // node.send({payload:results}) 
        let totalSecs = (new Date().getTime() - now.getTime()) / 1000
        // let threads = context.get("threads")
        let fulfilleds = results.filter(r => r.status === "fulfilled")
        let rejecteds = results.filter(r => r.status === "rejected")

        let fails = fulfilleds.filter(r => r.value.result === "error")
        let timeouts = fulfilleds.filter(r => r.value.result === "timeout")
